def transform_conditions(conditions_json: dict) -> dict:
    conditions = []
    for cond in conditions_json.get("conditions", []):
        c = dict(cond)
        if c.get("field") == "description":
            c["field"] = "trans_description"
        conditions.append(c)
    return {"conditions": conditions}


def sql_str(value: str | None) -> str:
    if value is None:
        return "NULL"
    return "'" + value.replace("\\", "\\\\").replace("'", "''") + "'"


def sql_json(obj: dict) -> str:
    raw = json.dumps(obj, ensure_ascii=False, separators=(",", ":"))
    return sql_str(raw)


def main() -> None:
    out = Path(__file__).with_name("classification_rules_active.sql")
    lines = [
        "-- Seed: aktywne reguły klasyfikacji (67 wierszy, active=1)",
        "-- Transformacja: field \"description\" -> \"trans_description\" w conditions_json",
        "-- Bez TRUNCATE/DELETE — uruchamiaj jednorazowo (duplikaty przy ponownym uruchomieniu).",
        "-- Wymagania FK: party_id=1, created_by/updated_by=2 (sprawdź: SELECT id, email FROM app_user).",
        "-- actions_json: wallet/concern/category/party muszą istnieć w docelowej bazie.",
        "-- created_from_transaction_id: wymaga istniejących transakcji lub ustaw NULL przed importem.",
        "-- Uruchomienie: docker compose exec -T db mariadb -usamfin -psamfin samfin < backend/data/seeds/classification_rules_active.sql",
        "",
        "SET NAMES utf8mb4;",
        "",
    ]

    for row in ROWS:
        conditions = transform_conditions(row["conditions_json"])
        actions = row["actions_json"]
        tx_id = row["created_from_transaction_id"]
        tx_sql = "NULL" if tx_id is None else str(tx_id)

        lines.append(
            "INSERT INTO classification_rule ("
            "party_id, name, description, priority, enabled, stop_on_match, "
            "conditions_json, actions_json, created_from_transaction_id, "
            "active, created_by, updated_by, created_at, updated_at"
            ") VALUES ("
            f"{row['party_id']}, "
            f"{sql_str(row['name'])}, "
            f"{sql_str(row['description'])}, "
            f"{row['priority']}, {row['enabled']}, {row['stop_on_match']}, "
            f"{sql_json(conditions)}, "
            f"{sql_json(actions)}, "
            f"{tx_sql}, "
            f"1, {row['created_by']}, {row['updated_by']}, "
            f"{sql_str(row['created_at'])}, "
            f"{sql_str(row['updated_at'])}"
            ");"
        )
        lines.append("")

    out.write_text("\n".join(lines), encoding="utf-8")
    print(f"Wrote {len(ROWS)} INSERTs to {out}")
    # sanity
    assert len(ROWS) == 67
    for row in ROWS:
        for cond in transform_conditions(row["conditions_json"])["conditions"]:
            assert cond["field"] != "description", f"id {row['id']} still has description field"


if __name__ == "__main__":
    main()
